ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?physicalmilestones ?cognitivemilestones ?childage WHERE {
  ?milestonerecords a :MilestoneRecords .
  ?milestonerecords p:physicalMilestones ?physicalmilestones .
  ?milestonerecords p:cognitiveMilestones ?cognitivemilestones .
  ?milestonerecords p:childAge ?childage .
  ?milestonerecords p:childAge ?childage_o .
}
ORDER BY ASC(?childage_o) }
  component: { SELECT ?cognitivemilestones ?childage WHERE {
  ?milestonerecords a :MilestoneRecords .
  ?milestonerecords p:cognitiveMilestones ?cognitivemilestones .
  ?milestonerecords p:childAge ?childage .
  ?milestonerecords p:childAge ?childage_o .
}
ORDER BY ASC(?childage_o) }
  component_2: { SELECT ?physicalmilestones ?childage WHERE {
  ?milestonerecords a :MilestoneRecords .
  ?milestonerecords p:physicalMilestones ?physicalmilestones .
  ?milestonerecords p:childAge ?childage .
  ?milestonerecords p:childAge ?childage_o .
}
ORDER BY ASC(?childage_o) }
}

PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
CHOICE vague {
  full: { SELECT ?pm ?cm (COUNT(?x) AS ?n) WHERE { ?x a :MilestoneRecords ; p:physicalMilestones ?pm ; p:cognitiveMilestones ?cm } GROUP BY ?pm ?cm }
  component: { SELECT (SAMPLE(?cognitivemilestones) AS ?cognitivemilestoness) (COUNT(*) AS ?agg) WHERE {
  ?milestonerecords a :MilestoneRecords .
  ?milestonerecords p:cognitiveMilestones ?cognitivemilestones .
} }
  component_2: { SELECT ?pm (COUNT(?x) AS ?n) WHERE { ?x a :MilestoneRecords ; p:physicalMilestones ?pm } GROUP BY ?pm }
}
